3430 bool DependenceInfo::tryDelinearizeParametricSize(
3431     Instruction *Src, Instruction *Dst, const SCEV *SrcAccessFn,
3432     const SCEV *DstAccessFn, SmallVectorImpl<const SCEV *> &SrcSubscripts,
3433     SmallVectorImpl<const SCEV *> &DstSubscripts) {
3434 
3435   const SCEVUnknown *SrcBase =
3436       dyn_cast<SCEVUnknown>(SE->getPointerBase(SrcAccessFn));
3437   const SCEVUnknown *DstBase =
3438       dyn_cast<SCEVUnknown>(SE->getPointerBase(DstAccessFn));
3439   assert(SrcBase && DstBase && SrcBase == DstBase &&
3440          "expected src and dst scev unknowns to be equal");
3441 
3442   const SCEV *ElementSize = SE->getElementSize(Src);
3443   if (ElementSize != SE->getElementSize(Dst))
3444     return false;
3445 
3446   const SCEV *SrcSCEV = SE->getMinusSCEV(SrcAccessFn, SrcBase);
3447   const SCEV *DstSCEV = SE->getMinusSCEV(DstAccessFn, DstBase);
3448 
3449   const SCEVAddRecExpr *SrcAR = dyn_cast<SCEVAddRecExpr>(SrcSCEV);
3450   const SCEVAddRecExpr *DstAR = dyn_cast<SCEVAddRecExpr>(DstSCEV);
3451   if (!SrcAR || !DstAR || !SrcAR->isAffine() || !DstAR->isAffine())
3452     return false;
3453 
3454   // First step: collect parametric terms in both array references.
3455   SmallVector<const SCEV *, 4> Terms;
3456   collectParametricTerms(*SE, SrcAR, Terms);
3457   collectParametricTerms(*SE, DstAR, Terms);
3458 
3459   // Second step: find subscript sizes.
3460   SmallVector<const SCEV *, 4> Sizes;
3461   findArrayDimensions(*SE, Terms, Sizes, ElementSize);
3462 
3463   // Third step: compute the access functions for each subscript.
3464   computeAccessFunctions(*SE, SrcAR, SrcSubscripts, Sizes);
3465   computeAccessFunctions(*SE, DstAR, DstSubscripts, Sizes);
3466 
3467   // Fail when there is only a subscript: that's a linearized access function.
3468   if (SrcSubscripts.size() < 2 || DstSubscripts.size() < 2 ||
3469       SrcSubscripts.size() != DstSubscripts.size())
3470     return false;
3471 
3472   // Statically check that the array bounds are in-range. The first subscript we
3473   // don't have a size for and it cannot overflow into another subscript, so is
3474   // always safe. The others need to be 0 <= subscript[i] < bound, for both src
3475   // and dst.
3476   // FIXME: It may be better to record these sizes and add them as constraints
3477   // to the dependency checks.
3478   if (!DisableDelinearizationChecks)
3479     if (!validateDelinearizationResult(*SE, Sizes, SrcSubscripts) ||
3480         !validateDelinearizationResult(*SE, Sizes, DstSubscripts))
3481       return false;
3482 
3483   return true;
3484 }
